import { useState, useEffect } from 'react';
import { contentService } from '../../services/cmsService';

export default function Testimonials() {
  const [testimonials, setTestimonials] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    contentService.getTestimonials()
      .then(data => {
        if (data) {
          setTestimonials(data);
        } else {
          // Fallback default testimonials
          setTestimonials([
            { id: 1, name: 'Jean-Pierre', company: 'Electricien.Auto', content: 'Service rapide et efficace. J\'ai économisé 200€ sur mon assurance.', rating: 5 },
            { id: 2, name: 'Marie L.', company: 'Artisan Electricien', content: 'Comparateur très simple d\'utilisation. Je recommande.', rating: 5 },
            { id: 3, name: 'Pierre D.', company: 'Dépanneur', content: 'Excellent rapport qualité-prix pour mon assurance professionnelle.', rating: 4 },
          ]);
        }
      })
      .catch(() => {
        setTestimonials([
          { id: 1, name: 'Jean-Pierre', company: 'Electricien.Auto', content: 'Service rapide et efficace.', rating: 5 },
          { id: 2, name: 'Marie L.', company: 'Artisan', content: 'Comparateur très simple.', rating: 5 },
        ]);
      })
      .finally(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <section className="py-16 bg-gray-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="animate-pulse">
            <div className="h-8 bg-gray-200 rounded w-64 mx-auto mb-12"></div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {[1, 2, 3].map(i => (
                <div key={i} className="bg-white rounded-xl p-6 h-48"></div>
              ))}
            </div>
          </div>
        </div>
      </section>
    );
  }

  return (
    <section className="py-16 md:py-20 bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-12">
          <h2 className="text-3xl md:text-4xl font-bold text-gray-900 mb-4">
            Ce que disent nos clients
          </h2>
          <p className="text-lg text-gray-600 max-w-2xl mx-auto">
            Des milliers d'artisans nous font confiance
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {testimonials.map((testimonial) => (
            <div 
              key={testimonial.id} 
              className="bg-white rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow"
            >
              <div className="flex items-center gap-1 mb-4">
                {[...Array(5)].map((_, i) => (
                  <i 
                    key={i} 
                    className={`fas fa-star ${
                      i < (testimonial.rating || 5) ? 'text-yellow-400' : 'text-gray-200'
                    }`}
                  ></i>
                ))}
              </div>
              <blockquote className="text-gray-700 mb-4">
                "{testimonial.content}"
              </blockquote>
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-yellow-100 rounded-full flex items-center justify-center">
                  <span className="text-yellow-600 font-bold">
                    {(testimonial.name || 'A')[0]}
                  </span>
                </div>
                <div>
                  <div className="font-medium text-gray-900">{testimonial.name}</div>
                  <div className="text-sm text-gray-500">{testimonial.company}</div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
